SELECT feedback_text, rating
FROM user_feedback
ORDER BY rating DESC;

SELECT user_id
FROM user_inputs
WHERE input_id = 'your_input_id_here';

SELECT uf.feedback_text, uf.rating
FROM user_feedback AS uf
WHERE uf.user_id = 0 AND uf.input_id = 1;

SELECT AVG(number_entities) AS average_entities_per_input
  FROM (
      SELECT input_id, COUNT(entity_id) AS number_entities
      FROM entities
      GROUP BY input_id
  );
